}

function pruneIfNeeded(now: number): void {
  if (BUCKETS.size < MAX_BUCKETS) return;
  for (const [k, b] of BUCKETS) {
    if (now - b.lastSeenMs > PRUNE_AFTER_MS) BUCKETS.delete(k);
    if (BUCKETS.size < MAX_BUCKETS * 0.8) break;
